### 7. HTTP/1.1 Connection Handling
```rust
/// HTTP/1.1 connection with keep-alive and shutdown.
async fn http1_connection(
    cx: &Cx<'_>,
    stream: TcpStream,
    shutdown: &ShutdownSignal,
) -> Outcome<(), ConnectionError> {
    let (reader, writer) = stream.split();

    // Connection-level budget (idle timeout)
    let budget = Budget::deadline(Instant::now() + config.idle_timeout);
    let cx = cx.with_budget(budget);

    loop {
        // Check for shutdown or idle timeout
        tokio::select! {
            _ = shutdown.wait() => {
                // Graceful close: finish current request, then close
                break;
            }
            result = read_request(&cx, &reader) => {
                match result {
                    Outcome::Ok(request) => {
                        // Reset idle timeout
                        let response = handle_request(&cx, request, shutdown).await?;
                        write_response(&cx, &writer, response).await?;

                        // Check keep-alive
                        if !response.headers().get("connection").map(|v| v == "keep-alive").unwrap_or(false) {
                            break;
                        }
                    }
                    Outcome::Cancelled(_) => break,  // Idle timeout
                    Outcome::Err(e) => return Outcome::Err(e.into()),
                    Outcome::Panicked(p) => return Outcome::Panicked(p),
                }
            }
        }
    }

    // Graceful TCP close
    stream.shutdown(&cx).await?;
    Ok(())
}
```

